// Calculate factorial (e.g., 5! = 5 * 4 * 3 * 2 * 1)
function factorial(n) {
  // 1. Base Case (Stopping condition)
  if (n === 1) return 1;

  // 2. Recursive Case (Calling itself with a smaller piece)
  return n * factorial(n - 1);
}

console.log(factorial(5)); // 120

